(function initContact() {
 
    const EMAILJS_PUBLIC_KEY  = "JPyeDNWtdVBljqT-I";   
    const EMAILJS_SERVICE_ID  = "service_j01sz6r";  
    const EMAILJS_TEMPLATE_ID = "template_nepz0ns";  
   
    emailjs.init({ publicKey: EMAILJS_PUBLIC_KEY });
   
    // expose to window so onclick handlers can reach them
    window.contactNextStep = function () {
      const name    = document.getElementById("contact-name").value.trim();
      const email   = document.getElementById("contact-email").value.trim();
      const subject = document.getElementById("contact-subject").value.trim();
   
      if (!name || !email || !subject) {
        alert("Please fill in your name, email, and subject before continuing.");
        return;
      }
   
      if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
        alert("Please enter a valid email address.");
        return;
      }
   
      document.getElementById("step1").classList.remove("active");
      document.getElementById("step2").classList.add("active");
      document.getElementById("stepCurrent").textContent = "02";
      document.getElementById("stepFill").style.width = "100%";
      document.getElementById("stepName").textContent = "PERSONAL · MESSAGE";
    };
   
    window.contactPrevStep = function () {
      document.getElementById("step2").classList.remove("active");
      document.getElementById("step1").classList.add("active");
      document.getElementById("stepCurrent").textContent = "01";
      document.getElementById("stepFill").style.width = "50%";
    };
   
    window.contactSend = function () {
      const name    = document.getElementById("contact-name").value.trim();
      const email   = document.getElementById("contact-email").value.trim();
      const subject = document.getElementById("contact-subject").value.trim();
      const phone   = document.getElementById("contact-phone").value.trim();
      const message = document.getElementById("contact-message").value.trim();
   
      if (!message) {
        alert("Please write your message before sending.");
        return;
      }
   
      const sendBtn = document.getElementById("sendBtn");
      sendBtn.disabled = true;
      sendBtn.innerHTML = '<i class="bi bi-hourglass-split"></i> Sending…';
   
      emailjs.send(EMAILJS_SERVICE_ID, EMAILJS_TEMPLATE_ID, {
        from_name:    name,
        from_email:   email,
        subject:      subject,
        phone:        phone || "Not provided",
        message:      message,
        to_email:     "allenendaya43@gmail.com",
      })
      .then(() => {
        document.getElementById("step2").classList.remove("active");
        document.getElementById("successEmail").textContent = email;
        document.getElementById("contactSuccess").classList.add("show");
        document.querySelector(".contact-step-bar").style.display = "none";
      })
      .catch((err) => {
        console.error("EmailJS error:", err);
        sendBtn.disabled = false;
        sendBtn.innerHTML = '<i class="bi bi-send-fill"></i> Send Message';
        alert("Something went wrong. Please try again or email me directly at allenendaya43@gmail.com");
      });
    };
   
  })();